### custom.map
###-----------

# showkey
# | is keycode 41
# - is keycode 58

alt keycode 41 = F13
alt keycode 53 = F14

# cat -v
# alt + |  returns:    ^[[1:2P  while TERM=xterm-256color   (inside tmux)
# alt + |  returns:    ^[[25~   while TERM=linux            (pure linux tty)
# alt + -  returns:    ^[[1:2Q  while TERM=xterm-256color
# alt + -  returns:    ^[[26~   while TERM=linux
